// 여러 파일 업로드를 개별 아이템으로 분리
const inputItem = $input.first();
const agencyName = inputItem.json['기관명'] || '';
const uploadedFiles = inputItem.json['파일을 업로드해주세요'] || [];
const binary = inputItem.binary || {};
const binaryKeys = Object.keys(binary);

if (uploadedFiles.length === 0) throw new Error('업로드된 파일이 없습니다.');

const items = [];
for (let i = 0; i < uploadedFiles.length; i++) {
  const binaryKey = binaryKeys[i];
  if (!binaryKey) continue;
  items.push({
    json: {
      fileIndex: i,
      filename: uploadedFiles[i].filename,
      agencyName,
      totalFiles: uploadedFiles.length
    },
    binary: { data: binary[binaryKey] }
  });
}

if (items.length === 0) throw new Error('바이너리 데이터를 찾을 수 없습니다.');
return items;

// Gemini Files API 응답에서 file_uri 추출 + generateContent 요청 바디 조립
// ※ JSON 전용 처리 — binary 접근 없음 (Task Runner 호환)
const results = [];
const uploadResults = $input.all();
const originalItems = $('파일 정규화').all();

for (let i = 0; i < uploadResults.length; i++) {
  const uploadItem = uploadResults[i];
  const originalItem = originalItems[i] || { json: {} };

  const fileUri = uploadItem.json?.file?.uri;
  const filename = originalItem.json.filename || `file_${i + 1}.pdf`;
  const fileIndex = originalItem.json.fileIndex ?? i;
  const agencyName = originalItem.json.agencyName ?? '';

  if (!fileUri) {
    throw new Error(`[${filename}] 파일 업로드 응답에 URI가 없습니다. 응답: ${JSON.stringify(uploadItem.json)}`);
  }

  const geminiRequestBody = {
    contents: [{
      parts: [
        {
          file_data: {
            mime_type: 'application/pdf',
            file_uri: fileUri
          }
        },
        {
          text: `파일명: "${filename}"\n\n이 PDF 파일의 전체 내용을 텍스트로 상세히 추출해주세요.\n- 표가 있으면 표의 내용을 텍스트로 정리해주세요.\n- 이미지·그래픽이 있으면 그 내용과 의미를 설명해주세요.\n- 원문에 충실하게 추출하되, 레이아웃·페이지 구분 마크업은 생략해도 됩니다.\n- 최대한 완전하게 추출해주세요.`
        }
      ]
    }],
    generationConfig: {
      maxOutputTokens: 8192
    }
  };

  results.push({
    json: {
      fileIndex,
      filename,
      agencyName,
      fileUri,
      geminiRequestBody
    }
  });
}

return results;

// Gemini generateContent 응답 파싱 + 파일 역할 판별 (본체 vs 보조자료)
return $input.all().map(item => {
  const filename = item.json.filename ?? '파일명 없음';

  // Gemini API 응답에서 추출 텍스트 가져오기
  const candidates = item.json.candidates;
  let extractedText = '';
  if (candidates?.[0]?.content?.parts?.[0]?.text) {
    extractedText = candidates[0].content.parts[0].text;
  }

  // 파일 역할 판별: 파일명에 아래 키워드가 포함되면 보조자료(support)
  const supportKeywords = [
    '계획서', '계획(안)', '계획안', '결과요약서', '결과보고서',
    '보고서(안)', '보조자료', '공문', '지침', '가이드', '증빙'
  ];
  const isSupport = supportKeywords.some(kw => filename.includes(kw));

  return {
    json: {
      fileIndex: item.json.fileIndex ?? 0,
      filename,
      agencyName: item.json.agencyName ?? '',
      role: isSupport ? 'support' : 'main',
      text: extractedText.trim().substring(0, 15000)
    }
  };
});

// 본체/보조자료 구분 → Gemini 프롬프트용 텍스트 조립
const inputData = $input.first().json;
const files = inputData.files || [];
const agencyName = (files[0] || {}).agencyName || '';

const mainFiles = files.filter(f => f.role === 'main');
const supportFiles = files.filter(f => f.role === 'support');

const mainText = mainFiles.length > 0
  ? '【주요 실적 파일 (본체 — 카드뉴스, 포스터, 교육결과물 등 실적 자체)】\n' +
    mainFiles.map((f, i) =>
      '[본체파일 ' + (i + 1) + '] ' + f.filename + '\n' + (f.text || '(내용 없음)')
    ).join('\n\n---\n\n')
  : '';

const supportText = supportFiles.length > 0
  ? '\n\n【보조 자료 파일 (계획서·계획(안)·결과요약서 등 실적을 설명하는 자료)】\n' +
    supportFiles.map((f, i) =>
      '[보조파일 ' + (i + 1) + '] ' + f.filename + '\n' + (f.text || '(내용 없음)')
    ).join('\n\n---\n\n')
  : '';

return [{
  json: {
    agencyName,
    fileCount: files.length,
    mainFileCount: mainFiles.length,
    supportFileCount: supportFiles.length,
    fileListText: (mainText + supportText).substring(0, 50000)
  }
}];

